mapper.select:
SELECT *
FROM notifications
WHERE msg_id = #{msgId}
  AND user_id = #{userId}
LIMIT 1

mapper.update:
UPDATE notifications
SET read_status = 1,
    read_at = NOW()
WHERE id = #{id}
  AND user_id = #{userId}

mapper.select:
SELECT *
FROM notifications
WHERE user_id = #{userId}

    AND read_status = #{readStatus}

ORDER BY priority DESC, created_at DESC

mapper.delete:
DELETE FROM notifications
WHERE id = #{id}
  AND user_id = #{userId}
